sql:
SELECT player_id, homeruns 
FROM player_batting 
WHERE homeruns = (
  SELECT MAX(homeruns) 
  FROM player_batting
);

SELECT pb.player_id, p.player_name, pb.runs
FROM player_batting pb
JOIN players p ON pb.player_id = p.player_id
WHERE pb.runs = (
    SELECT MAX(runs) FROM player_batting
);

SELECT AVG(salary) 
FROM players 
WHERE player_id IN (
    SELECT player_id 
    FROM player_seasons
);

SELECT COUNT(DISTINCT pt.player_id) AS players_count
FROM player_teams pt
WHERE pt.last_game_played <= '1975-12-31';

SELECT batting_average 
FROM player_batting 
WHERE player_id = '1' AND season_id = 1;

SELECT player_id, COUNT(*) as number_of_seasons
FROM player_seasons
GROUP BY player_id;

external_knowledge:
- A batting average greater than 0.300 is considered excellent in professional baseball; 
- A salary of $20 million is relatively high for baseball players; 
- An active contract implies that the player is still playing and is not retired.
